const campaigns = $json.data || [];
if (!Array.isArray(campaigns) || campaigns.length === 0) return [];

return campaigns.map(c => ({
  ad_account_id: $json.ctx.ad_account_id,
  report_sheet_url: $json.ctx.report_sheet_url,

sheet_list: $json.sheet_list,
  // дата отчёта из Meta
  report_date: c.date_start,

  // метрики
  campaign_name: c.campaign_name,
  spend: Number(c.spend),
  impressions: Number(c.impressions),
  clicks: Number(c.clicks),
  ctr: Number(c.ctr),
  cpm: Number(c.cpm),
  cpc: Number(c.cpc),

  date_start: c.date_start,
  date_stop: c.date_stop,
}));

const url = $json.report_sheet_url;
if (!url) throw new Error('report_sheet_url пустой');

const match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
if (!match) throw new Error('Не нашла spreadsheetId в ссылке');

return [{
  ...$json,
  report_spreadsheet_id: match[1],
}];

return [{
  ...$json,
  ctx: {
    client_id: $json.client_id,
    client_name: $json.client_name,
    timezone: $json.timezone,
    ad_account_id: $json.ad_account_id,
    report_sheet_url: $json.report_sheet_url,
    meta_access_token: $json.meta_access_token,
    metrics_level: $json.metrics_level,
  }
}];

const rows = $input.all();
const first = rows[0]?.json || {};

// Detect client
const clientName =
  first.client_name ||
  first.ctx?.client_name ||
  "Client";

const clientId =
  first.client_id ||
  first.ctx?.client_id ||
  first.ad_account_id ||
  first.ctx?.ad_account_id ||
  "N/A";

// Detect report date
const reportDate =
  first.report_date ||
  first.date_start ||
  "Yesterday";

let message = `📊 Meta Ads Daily Summary\n`;
message += `👤 Client: ${clientName} (ID: ${clientId})\n`;
message += `📅 Date: ${reportDate}\n\n`;

let totalSpend = 0;
let totalImpressions = 0;
let totalClicks = 0;

for (const r of rows) {
  totalSpend += Number(r.json.spend || 0);
  totalImpressions += Number(r.json.impressions || 0);
  totalClicks += Number(r.json.clicks || 0);
}

const totalCTR = totalImpressions ? (totalClicks / totalImpressions) * 100 : 0;
const totalCPC = totalClicks ? (totalSpend / totalClicks) : 0;

message += `💰 Total Spend: ${totalSpend.toFixed(1)}\n`;
message += `👀 Impressions: ${totalImpressions}\n`;
message += `🖱 Clicks: ${totalClicks}\n`;
message += `📈 CTR: ${totalCTR.toFixed(1)}%\n`;
message += `💲 CPC: ${totalCPC.toFixed(2)}\n\n`;
message += `-------------------------\n\n`;

for (const r of rows) {
  const name = r.json.campaign_name ?? "(no campaign_name)";
  const spend = Number(r.json.spend || 0);
  const ctr = Number(r.json.ctr || 0);
  const cpc = Number(r.json.cpc || 0);

  let status = "✅ OK";
  if (ctr < 1.5) status = "❌ Weak creative (low CTR)";
  else if (cpc > 0.5) status = "⚠ Expensive click (high CPC)";
  else if (ctr >= 2 && cpc <= 0.5) status = "🔥 Good candidate to scale";

  message += `🎯 ${name}\n`;
  message += `💰 Spend: ${spend.toFixed(1)}\n`;
  message += `📈 CTR: ${ctr.toFixed(1)}%\n`;
  message += `💲 CPC: ${cpc.toFixed(2)}\n`;
  message += `➡ ${status}\n\n`;
}

const reportUrl = first.report_sheet_url || first.ctx?.report_sheet_url;

if (reportUrl) {
  message += `🔗 Report: ${reportUrl}`;
}

return [{ json: { message } }];
